const { suggestFlags } = require('feature-flag-automation');
const pr = $input.item.json;
const flags = await suggestFlags(pr.diff || '', pr.context || '');
return [{json: {pr, suggestedFlags: flags}}];

const flags = $input.item.json.suggestedFlags;
const created = [];
for (const flag of flags) {
  const result = await require('feature-flag-automation').createFlag('default', flag.flag_key, flag.name, `AI-suggested: ${flag.name}`);
  await require('feature-flag-automation').setPercentageRollout(flag.flag_key, 5);
  created.push(flag.flag_key);
}
return [{json: {createdFlags: created}}];
